// // This module decrements the 4-bit count on each positive edge of the clock signal 'clk' and resets to all ones when the reset signal 'rst' is high.
module binary_counter_4bit(
	input clk,
	input rst,
	output reg [3:0] count
);

	always @(posedge clk or posedge rst) begin
		if (rst) begin
			count <= 4'b0000;
		end
		else begin
			count <= count + 1;
		end
	end

endmodule
